action.old_str:
void
EmitIR::operator()(ReturnStmt* obj)
{
  auto& irb = *mCurIrb;
  if (!obj->expr) {
    irb.CreateRetVoid();
  } else {
    auto retVal = self(obj->expr);
    irb.CreateRet(retVal);
  }
  auto exitBb = llvm::BasicBlock::Create(mCtx, "return_exit", mCurFunc);
  irb.SetInsertPoint(exitBb);
}

action.new_str:
void
EmitIR::operator()(ReturnStmt* obj)
{
  auto& irb = *mCurIrb;
  if (obj->expr) {
    auto retVal = self(obj->expr);
    auto retvalAlloca = mSymtbl["retval"];
    if (retvalAlloca) {
      irb.CreateStore(retVal, retvalAlloca);
      irb.CreateBr(mReturnBb);
    } else {
      irb.CreateRet(retVal);
    }
  } else {
    irb.CreateRetVoid();
  }
  auto exitBb = llvm::BasicBlock::Create(mCtx, "return_exit", mCurFunc);
  irb.SetInsertPoint(exitBb);
}

